@MainActor
final class WalletViewModel: ObservableObject {
    @Published var hasWallet: Bool = false
    @Published var address: String = ""
    @Published var balanceText: String = "--"
    @Published var signedTransaction: String?
    @Published var statusMessage: String?

    private let keyManager = KeyManager()
    private let transactionSigner = TransactionSigner()
    private let blockchainClient = BlockchainClient()

    private var privateKeyData: Data?
    private var demoTransaction: Transaction?

    init() {
        loadExistingWallet()
    }

    func loadExistingWallet() {
        if let stored = KeyManager.loadPrivateKey() {
            privateKeyData = stored
            hasWallet = true
            address = WalletAddressGenerator.address(from: stored)
            statusMessage = "Loaded existing wallet."
            refreshBalance()
        }
    }

    func createWallet() {
        let privateKey = keyManager.generatePrivateKey()
        KeyManager.savePrivateKey(privateKey)
        privateKeyData = privateKey
        address = WalletAddressGenerator.address(from: privateKey)
        hasWallet = true
        signedTransaction = nil
        statusMessage = "Wallet created."
        refreshBalance()
    }

    func prepareDemoTransaction() {
        guard privateKeyData != nil else {
            statusMessage = "Create wallet first."
            return
        }
        demoTransaction = Transaction(
            from: address,
            to: "0x000000000000000000000000000000000000dEaD",
            amount: 0.001,
            nonce: Int(Date().timeIntervalSince1970),
            gasPrice: 1,
            gasLimit: 21000,
            chainID: 1
        )
        statusMessage = "Demo transaction prepared."
    }

    func signPreparedTransaction() {
        guard let privateKey = privateKeyData, let transaction = demoTransaction else {
            statusMessage = "Prepare transaction first."
            return
        }
        do {
            let signed = try transactionSigner.sign(transaction: transaction, privateKey: privateKey)
            signedTransaction = signed.hexEncodedString()
            statusMessage = "Transaction signed."
            Task {
                await submitSignedTransaction(signed)
            }
        } catch {
            statusMessage = "Signing failed."
        }
    }

    func refreshBalance() {
        guard hasWallet else { return }
        Task {
            do {
                let balance = try await blockchainClient.fetchBalance(address: address)
                balanceText = String(format: "%.6f", balance)
                statusMessage = "Balance updated."
            } catch {
                balanceText = "--"
                statusMessage = "Balance unavailable."
            }
        }
    }

    func submitSignedTransaction(_ rawTx: Data) async {
        do {
            let txHash = try await blockchainClient.broadcastSignedTransaction(rawTransaction: rawTx)
            statusMessage = "Broadcasted: \(txHash)"
        } catch {
            statusMessage = "Broadcast failed."
        }
    }
}

final class KeyManager {
    private static let keychainService = "CryptoWalletMVP"
    private static let keychainAccount = "privateKey"

    func generatePrivateKey() -> Data {
        var key = Data(count: 32)
        _ = key.withUnsafeMutableBytes { SecRandomCopyBytes(kSecRandomDefault, 32, $0.baseAddress!) }
        return key
    }

    func storeInKeychain(_ data: Data) -> Bool {
        savePrivateKey(data)
        return true
    }

    static func savePrivateKey(_ data: Data) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: keychainAccount,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }

    static func loadPrivateKey() -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: keychainAccount,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess else { return nil }
        return result as? Data
    }
}

struct WalletAddressGenerator {
    static func address(from privateKey: Data) -> String {
        let hash = SHA256.hash(data: privateKey)
        return "0x" + hash.compactMap { String(format: "%02x", $0) }.joined().prefix(40)
    }
}

struct Transaction: Codable {
    let from: String
    let to: String
    let amount: Double
    let nonce: Int
    let gasPrice: Int
    let gasLimit: Int
    let chainID: Int
}

final class TransactionSigner {
    func sign(transaction: Transaction, privateKey: Data) throws -> Data {
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.sortedKeys]
        let txData = try encoder.encode(transaction)
        var digestInput = Data()
        digestInput.append(privateKey)
        digestInput.append(txData)
        let digest = SHA256.hash(data: digestInput)
        return Data(digest)
    }
}

final class BlockchainClient {
    func fetchBalance(address: String) async throws -> Double {
        let apiURL = URL(string: "https://example.com/balance?address=\(address)")!
        var request = URLRequest(url: apiURL)
        request.httpMethod = "GET"
        _ = try await URLSession.shared.data(for: request)
        return Double.random(in: 0...10)
    }

    func broadcastSignedTransaction(rawTransaction: Data) async throws -> String {
        let apiURL = URL(string: "https://example.com/broadcast")!
        var request = URLRequest(url: apiURL)
        request.httpMethod = "POST"
        request.httpBody = rawTransaction
        request.setValue("application/octet-stream", forHTTPHeaderField: "Content-Type")
        _ = try await URLSession.shared.data(for: request)
        return rawTransaction.hexEncodedString()
    }
}

extension Data {
    func hexEncodedString() -> String {
        map { String(format: "%02x", $0) }.joined()
    }
}